import{_ as a,o as r,c as t,a2 as n}from"./chunks/framework.CKCxdkvf.js";const d=JSON.parse('{"title":"ADR-010 — Keplerian half-ellipses for transfer arc","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-010.md","filePath":"adr/ADR-010.md"}'),o={name:"adr/ADR-010.md"};function s(i,e,l,c,h,p){return r(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="adr-010-—-keplerian-half-ellipses-for-transfer-arc" tabindex="-1">ADR-010 — Keplerian half-ellipses for transfer arc <a class="header-anchor" href="#adr-010-—-keplerian-half-ellipses-for-transfer-arc" aria-label="Permalink to &quot;ADR-010 — Keplerian half-ellipses for transfer arc&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-04-15 TA anchor · §components/fly-screen · §constraints</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>The fly screen needs to draw the spacecraft&#39;s transfer trajectory between Earth and Mars. An approximation is needed — a full n-body propagation is out of scope.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>The transfer arc is computed as a Keplerian half-ellipse using the actual semi-major axis and eccentricity of the Earth-Mars Hohmann transfer ellipse. The outbound arc sweeps true anomaly ν: 0→π. The return arc sweeps ν: π→2π on a second ellipse oriented so its perihelion aligns with Earth&#39;s actual position at the return date.</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>Bezier curves were the original implementation. They produced arcs that passed through the Sun, required manual tuning of control points, and broke whenever the Earth-Mars geometry changed. A Keplerian ellipse is physically correct, parameterised by the actual orbital mechanics, and never intersects the Sun. The perihelion-of-return-orbit targeting Earth&#39;s actual return position ensures the spacecraft ends at Earth&#39;s real location on the return date — not where Earth was at departure.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li>Bezier curves — fast to implement; geometrically wrong; passes through the Sun in some configurations; rejected.</li><li>Full Lambert propagation for the arc — would produce a more accurate trajectory shape; requires computing the full transfer ellipse from the Lambert solution. Acceptable future refinement; current Keplerian half-ellipse is correct to first order.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p>Positive: arc is physically correct; never intersects the Sun; parametric — automatically adapts to different launch windows. Negative: the return arc is an approximation (uses same transfer ellipse as outbound, not a separate Lambert solution for the return leg). Good enough for educational purposes.</p>',12)])])}const f=a(o,[["render",s]]);export{d as __pageData,f as default};
